import { describe, expect, it, vi } from "vitest";

let hasCookie = true;
vi.mock("next/headers", () => ({
  cookies: () => ({ get: () => (hasCookie ? { value: "r-pilot-1" } : undefined) }),
}));

import { GET } from "./route";

interface ProfilePayload {
  retailer: {
    id: string;
    name: string;
    ownerName: string;
    licenseNumber: string;
    storeName: string;
    storeAddress: string;
    phone: string;
    email: string;
    gstin: string;
    favouritesCount: number;
  };
  outstanding: {
    totalPaise: number;
    perDistributor: Array<{ distributor: { id: string; name: string }; amountPaise: number }>;
  };
}

describe("GET /api/profile", () => {
  it("returns 401 without a cookie", async () => {
    hasCookie = false;
    const res = await GET();
    expect(res.status).toBe(401);
    hasCookie = true;
  });

  it("returns the seeded retailer + outstanding payment shape", async () => {
    const res = await GET();
    expect(res.status).toBe(200);
    const body = (await res.json()) as ProfilePayload;
    expect(body.retailer.id).toBe("r-pilot-1");
    expect(body.retailer.licenseNumber).toBe("MH-RP-2024-7821");
    expect(body.retailer.favouritesCount).toBeGreaterThan(0);
    expect(body.outstanding.totalPaise).toBe(
      body.outstanding.perDistributor.reduce((acc, p) => acc + p.amountPaise, 0),
    );
  });
});

import { describe, expect, it, vi } from "vitest";
